// 網格圖 DFS/BFS 模板
int dirs[4][2] = {{0, 1}, {0, -1}, {1, 0}, {-1, 0}};

// DFS 遍歷連通塊
void dfs(vector<vector<int>>& grid, int x, int y) {
    int m = grid.size(), n = grid[0].size();
    grid[x][y] = 0; // 標記已訪問
    for (auto& d : dirs) {
        int nx = x + d[0], ny = y + d[1];
        if (nx >= 0 && nx < m && ny >= 0 && ny < n && grid[nx][ny]) {
            dfs(grid, nx, ny);
        }
    }
}

// BFS 求最短路
int bfs(vector<vector<int>>& grid, int sx, int sy, int tx, int ty) {
    int m = grid.size(), n = grid[0].size();
    queue<pair<int, int>> q;
    q.push({sx, sy});
    grid[sx][sy] = 0;
    int step = 0;
    while (!q.empty()) {
        int sz = q.size();
        while (sz--) {
            auto [x, y] = q.front();
            q.pop();
            if (x == tx && y == ty) {
                return step;
            }
            for (auto& d : dirs) {
                int nx = x + d[0], ny = y + d[1];
                if (nx >= 0 && nx < m && ny >= 0 && ny < n && grid[nx][ny]) {
                    grid[nx][ny] = 0;
                    q.push({nx, ny});
                }
            }
        }
        step++;
    }
    return -1;
}
